SELECT COUNT(*) AS total_servidores FROM servidor s WHERE LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) = LOWER('matematica') AND LOWER(s.sigla_campus) = LOWER('jat') AND s.pk_siape IN (SELECT chm.siape FROM calc_hora_aula_media chm WHERE chm.ano = 2024 AND chm.semestre = 2 AND LOWER(chm.sigla_campus) = LOWER('jat') AND LOWER(chm.area_ingresso) = LOWER('matematica'))